parameters.jsCode:
const extract = $('Extract Fields5').item.json || {};

const taskId =
  $json.task_id ||
  $json.taskId ||
  $json.operational_id ||
  $json.id ||
  "UNKNOWN-ID";

const rawTask =
  $json.task_summary ||
  $json.task_description ||
  extract.task_description ||
  $json.raw_payload?.task_description ||
  "";

const deadlineRaw =
  $json.deadline ||
  extract.deadline ||
  "";

const deadline = String(deadlineRaw).toLowerCase();

const clientName =
  $json.name ||
  $json.client_name ||
  $json.raw_payload?.name ||
  $json.body?.name ||
  "Unknown client";

const clientEmail =
  $json.client_email ||
  $json.email ||
  $json.to ||
  $json.raw_payload?.client_email ||
  $json.raw_payload?.email ||
  $json.body?.client_email ||
  $json.body?.email ||
  "";

const company =
  $json.company ||
  $json.raw_payload?.company ||
  $json.body?.company ||
  "";

const source =
  $json.source ||
  $json.raw_payload?.source ||
  $json.body?.source ||
  "unknown";

/* --------------------------
   CLIENT BUDGET
   user-submitted budget only
-------------------------- */

const clientBudgetRaw =
  $json.client_budget ||
  $json.budget ||
  $json.clientBudget ||
  $json.project_budget ||
  $json.estimatedBudget ||
  extract.client_budget ||
  extract.budget ||
  extract.clientBudget ||
  extract.project_budget ||
  extract.estimatedBudget ||
  $json.raw_payload?.client_budget ||
  $json.raw_payload?.budget ||
  $json.raw_payload?.clientBudget ||
  $json.raw_payload?.project_budget ||
  $json.raw_payload?.estimatedBudget ||
  $json.body?.client_budget ||
  $json.body?.budget ||
  $json.body?.clientBudget ||
  $json.body?.project_budget ||
  $json.body?.estimatedBudget ||
  "";

const clientBudget = String(clientBudgetRaw || "").trim();

function formatClientBudget(value) {
  const raw = String(value || "").trim();
  if (!raw) return "Not provided";

  const cleaned = raw
    .replace(/^€\s*/i, "")
    .replace(/\s+/g, " ")
    .trim();

  if (!cleaned) return "Not provided";

  if (/^\d+([.,]\d+)?$/.test(cleaned)) {
    return `€${cleaned}`;
  }

  return cleaned;
}

const clientBudgetDisplay = formatClientBudget(clientBudget);

let links = "";

if (Array.isArray($json.links)) {
  links = $json.links.join("\n");
} else if (typeof $json.links === "string") {
  links = $json.links.replace(/"/g, "");
} else if (extract.files_link) {
  links = extract.files_link.replace(/"/g, "");
}

function normalizeAttachmentNames(value) {
  if (!value) return [];

  let parsed = value;

  if (typeof parsed === "string") {
    const trimmed = parsed.trim();

    if (!trimmed || trimmed === "[]") return [];

    try {
      parsed = JSON.parse(trimmed);
    } catch (error) {
      parsed = trimmed.split(/[,\n]/);
    }
  }

  if (!Array.isArray(parsed)) {
    parsed = [parsed];
  }

  return parsed
    .map((item) => {
      if (!item) return "";

      if (typeof item === "string") {
        const trimmed = item.trim();

        if (!trimmed) return "";

        try {
          const nested = JSON.parse(trimmed);

          if (nested && typeof nested === "object") {
            return (
              nested.name ||
              nested.filename ||
              nested.fileName ||
              ""
            );
          }
        } catch (error) {
          return trimmed.replace(/^['"]|['"]$/g, "");
        }

        return trimmed.replace(/^['"]|['"]$/g, "");
      }

      if (typeof item === "object") {
        return (
          item.name ||
          item.filename ||
          item.fileName ||
          ""
        );
      }

      return "";
    })
    .map((name) => String(name).trim())
    .filter(Boolean);
}

const attachmentsDisplay = Array.from(
  new Set([
    ...normalizeAttachmentNames($json.attachments),
    ...normalizeAttachmentNames(extract.attachments),
    ...normalizeAttachmentNames($json.raw_payload?.attachments),
    ...normalizeAttachmentNames($json.body?.attachments)
  ])
).join(", ");

function getSection(label) {
  const regex = new RegExp(
    `${label}:\\s*([\\s\\S]*?)(?=\\n\\s*(Context|Tone|Goal|Files):|$)`,
    "i"
  );

  const match = rawTask.match(regex);

  if (!match) return "";

  return match[1].trim();
}

const cleanTask = rawTask
  .split(/\n\s*Context:|\n\s*Tone:|\n\s*Goal:|\n\s*Files:/i)[0]
  .trim();

const clientEmailTaskDescription =
  cleanTask || String(rawTask || "").trim();

const context = getSection("Context");
const tone = getSection("Tone");
const goal = getSection("Goal");

const task = cleanTask.toLowerCase();

let task_type = "general_task";
let suggested_quote = 99;
let priority = "Normal";
let complexity = "small";

const has = (words) =>
  words.some((w) => task.includes(w));

/* --------------------------
   TASK TYPE
-------------------------- */

if (
  has([
    "website",
    "web",
    "landing page",
    "framer",
    "seo",
    "shopify",
    "products",
    "webshop",
    "ecommerce"
  ])
) {
  task_type = "web_update";
  suggested_quote = 249;
}

else if (
  has([
    "automation",
    "workflow",
    "n8n",
    "zapier",
    "api"
  ])
) {
  task_type = "automation";
  suggested_quote = 299;
}

else if (
  has([
    "presentation",
    "deck",
    "slides",
    "pitch"
  ])
) {
  task_type = "presentation";
  suggested_quote = 199;
}

else if (
  has([
    "research",
    "analyse",
    "analysis",
    "market",
    "competitor"
  ])
) {
  task_type = "research";
  suggested_quote = 149;
}

else if (
  has([
    "pdf",
    "proposal",
    "document",
    "rewrite",
    "proofread"
  ])
) {
  task_type = "document";
  suggested_quote = 129;
}

else if (
  has([
    "social",
    "caption",
    "tiktok",
    "instagram",
    "linkedin"
  ])
) {
  task_type = "social_content";
  suggested_quote = 149;
}

/* --------------------------
   COMPLEXITY
-------------------------- */

if (cleanTask.length > 500) {
  complexity = "medium";
  suggested_quote += 75;
}

if (cleanTask.length > 1200) {
  complexity = "large";
  suggested_quote += 150;
}

/* --------------------------
   PRIORITY
-------------------------- */

if (
  deadline.includes("tonight") ||
  deadline.includes("today") ||
  deadline.includes("urgent") ||
  deadline.includes("rush") ||
  deadline.includes("4 hours") ||
  deadline.includes("4h")
) {
  priority = "High";
  suggested_quote += 50;
}

suggested_quote =
  Math.round(suggested_quote / 10) * 10 - 1;

const prettySource =
  source.replace(/_/g, " ");

const prettyType =
  task_type.replace(/_/g, " ");

/* --------------------------
   LANGUAGE STABILIZATION
   explicit locale always wins
-------------------------- */

function normalizeExplicitLocale(value) {
  const locale = String(value || "").trim().toLowerCase();
  if (!locale) return "";
  if (locale.startsWith("en")) return "en";
  if (locale.startsWith("nl")) return "nl";
  return "";
}

const explicitLocaleCandidates = [
  extract.preferred_language,
  extract.client_locale,
  extract.language,
  extract.lang,
  extract.source_language,

  $json.preferred_language,
  $json.client_locale,
  $json.language,
  $json.lang,
  $json.source_language,

  $json.raw_payload?.preferred_language,
  $json.raw_payload?.client_locale,
  $json.raw_payload?.language,
  $json.raw_payload?.lang,
  $json.raw_payload?.source_language,

  $json.body?.preferred_language,
  $json.body?.client_locale,
  $json.body?.language,
  $json.body?.lang,
  $json.body?.source_language
];

let explicitLanguage = "";
for (const candidate of explicitLocaleCandidates) {
  explicitLanguage = normalizeExplicitLocale(candidate);
  if (explicitLanguage) break;
}

const inferredDutch =
  /\b(ik|mijn|uw|jouw)\b/.test(task) ||
  task.includes("aanvraag") ||
  task.includes("offerte") ||
  task.includes("website laten maken") ||
  task.includes("automatisering") ||
  task.includes("automatiser") ||
  task.includes("spoed") ||
  task.includes("vandaag") ||
  task.includes("morgen");

const inferredEnglish =
  /\b(my|business|client)\b/.test(task) ||
  task.includes("website") ||
  task.includes("landing page") ||
  task.includes("automation") ||
  task.includes("onboarding") ||
  task.includes("before tomorrow") ||
  task.includes("next week");

const preferredLanguage =
  explicitLanguage ||
  (inferredDutch ? "nl" : inferredEnglish ? "en" : "en");

/* --------------------------
   EMAIL COPY
-------------------------- */

const clientEmailCopy = {
  en: {
    subject: "DONEOVERNIGHT — Task received",
    status_label: "● OPERATIONS ACTIVE",
    hero_title: "Task received.",
    greeting: "Hi",
    review_intro: "Your request is now under review.",
    review_lead: "We’re currently reviewing:",
    scope_label: "scope",
    timeline_label: "timeline",
    complexity_label: "complexity",
    deliverables_label: "deliverables",
    submitted_task_label: "Submitted Task",
    attachments_label: "Attachments",
    no_attachments: "No attachments included",
    deadline_label: "Deadline",
    review_window_label: "Review Window",
    review_window_value: "< 60 min",
    cta: "Track Review",
    footer: "PRIVATE OPERATING LAYER"
  },

  nl: {
    subject: "DONEOVERNIGHT — Aanvraag ontvangen",
    status_label: "● INTAKE ACTIEF",
    hero_title: "Aanvraag ontvangen.",
    greeting: "Hallo",
    review_intro: "Uw aanvraag wordt beoordeeld.",
    review_lead: "We bekijken op dit moment:",
    scope_label: "scope",
    timeline_label: "planning",
    complexity_label: "complexiteit",
    deliverables_label: "oplevering",
    submitted_task_label: "Ingediende aanvraag",
    attachments_label: "Bijlagen",
    no_attachments: "Geen bestanden toegevoegd",
    deadline_label: "Deadline",
    review_window_label: "Review",
    review_window_value: "< 60 min",
    cta: "Voortgang bekijken",
    footer: "PRIVATE UITVOERING"
  }
};

const clientEmailText =
  clientEmailCopy[preferredLanguage] ||
  clientEmailCopy.en;

const reviewToken =
  $json.review_token ||
  $json.reviewToken ||
  extract.review_token ||
  extract.reviewToken ||
  $json.raw_payload?.review_token ||
  $json.raw_payload?.reviewToken ||
  $json.body?.review_token ||
  $json.body?.reviewToken ||
  "";

const providedReviewUrl =
  $json.client_review_url ||
  $json.review_url ||
  $json.reviewUrl ||
  extract.client_review_url ||
  extract.review_url ||
  extract.reviewUrl ||
  $json.raw_payload?.client_review_url ||
  $json.raw_payload?.review_url ||
  $json.raw_payload?.reviewUrl ||
  $json.body?.client_review_url ||
  $json.body?.review_url ||
  $json.body?.reviewUrl ||
  "";

function buildQuery(params) {
  return Object.entries(params)
    .filter(([_, value]) =>
      value !== undefined &&
      value !== null &&
      String(value).trim() !== ""
    )
    .map(([key, value]) =>
      `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`
    )
    .join("&");
}

const reviewParams = {
  lang: preferredLanguage,
  state: "request_received",
  task_id: taskId
};

if (reviewToken) {
  reviewParams.token = reviewToken;
}

const generatedReviewUrl =
  `https://portal.doneovernight.com/review?${buildQuery(reviewParams)}`;

const clientReviewUrl =
  providedReviewUrl || generatedReviewUrl;

/* --------------------------
   TELEGRAM
-------------------------- */

const parts = [];

parts.push("🟡 NEW TASK INTAKE");

parts.push(`📝 Task:
${cleanTask}`);

if (context) {
  parts.push(`📚 Context:
${context}`);
}

if (tone) {
  parts.push(`🎨 Tone:
${tone}`);
}

if (goal) {
  parts.push(`🎯 Goal:
${goal}`);
}

if (links) {
  parts.push(`🔗 Links:
${links}`);
}

if (attachmentsDisplay) {
  parts.push(`📎 Attachments:
${attachmentsDisplay}`);
}

parts.push(`—
👤 Client: ${clientName}
📧 ${clientEmail || "Unknown email"}`);

if (company) {
  parts.push(`🏢 ${company}`);
}

parts.push(`⏳ Deadline: ${$json.deadline || deadlineRaw || "Not provided"}
⚡ Priority: ${priority}
📡 Source: ${prettySource}
💸 Client budget: ${clientBudgetDisplay}

📁 Type: ${prettyType.toUpperCase()} · ${complexity.toUpperCase()}
💰 Internal estimate: €${suggested_quote}

—
🆔 Operational ID: ${taskId}
Created: ${$json.created_at || $json.createdAt || new Date().toISOString()}

Actions:
Accept → /accept ${taskId}
Reject → /reject ${taskId}
Quote → /quote ${suggested_quote} ${taskId}`);

return {
  json: {
    ...$json,

    preferred_language: preferredLanguage,
    client_locale: preferredLanguage,
    language: preferredLanguage,
    lang: preferredLanguage,

    client_budget: clientBudget,
    client_budget_display: clientBudgetDisplay,

    attachments_display:
      attachmentsDisplay ||
      clientEmailText.no_attachments,

    client_email_task_description:
      clientEmailTaskDescription,

    client_email_subject:
      clientEmailText.subject,

    client_email_copy: {
      ...clientEmailText
    },

    review_token: reviewToken,

    client_review_url:
      clientReviewUrl,

    telegram_message:
      parts.filter(Boolean).join("\n\n")
  }
};

parameters.bodyContent:
=<html>
  <body style="margin:0;padding:0;background:#050505;font-family:Arial,sans-serif;color:#f5f5f5;">

    <!-- PREHEADER -->
    <div style="
      display:none;
      max-height:0;
      overflow:hidden;
      opacity:0;
      color:transparent;
      mso-hide:all;
    ">
      {{ $('Code in JavaScript5').item.json.client_email_copy.review_intro }}
    </div>

    <table width="100%" cellpadding="0" cellspacing="0" border="0" style="
      background:#050505;
      padding:40px 20px;
    ">
      <tr>
        <td align="center">

          <table width="640" cellpadding="0" cellspacing="0" border="0" style="
            width:640px;
            max-width:640px;
            background:#0b0b0b;
            border:1px solid #1a1a1a;
            border-radius:28px;
            overflow:hidden;
          ">

            <!-- HEADER -->
            <tr>
              <td align="center" style="
                padding:52px 42px 20px 42px;
                background:#0b0b0b;
              ">

                <picture>
                  <source
                    srcset="https://doneovernight.com/brand/doneovernight-white.png"
                    media="(prefers-color-scheme: dark)"
                  />

                  <source
                    srcset="https://doneovernight.com/brand/doneovernight-black.png"
                    media="(prefers-color-scheme: light)"
                  />

                  <img 
                    src="https://doneovernight.com/brand/doneovernight-neutral.png"
                    alt="DONEOVERNIGHT"
                    width="240"
                    style="
                      display:block;
                      width:240px;
                      max-width:100%;
                      height:auto;
                      border:0;
                      outline:none;
                      text-decoration:none;
                      -ms-interpolation-mode:bicubic;
                    "
                  />
                </picture>

              </td>
            </tr>

            <!-- HERO -->
            <tr>
              <td style="padding:0 52px;">

                <div style="
                  background:#111111;
                  border:1px solid rgba(255,255,255,0.06);
                  border-radius:22px;
                  padding:34px;
                ">

                  <div style="
                    color:#7ee2b8;
                    font-size:11px;
                    letter-spacing:4px;
                    text-transform:uppercase;
                    margin-bottom:18px;
                    font-weight:600;
                  ">
                    {{ $('Code in JavaScript5').item.json.client_email_copy.status_label }}
                  </div>

                  <div style="
                    font-size:46px;
                    line-height:1.05;
                    font-weight:700;
                    color:#ffffff;
                    letter-spacing:-1px;
                    margin-bottom:22px;
                  ">
                    {{ $('Code in JavaScript5').item.json.client_email_copy.hero_title }}
                  </div>

                  <div style="
                    font-size:18px;
                    line-height:1.9;
                    color:#b7b7b7;
                  ">

                    {{ $('Code in JavaScript5').item.json.client_email_copy.greeting }}
                    {{ $('Extract Fields5').item.json.name }},

                    <br><br>

                    {{ $('Code in JavaScript5').item.json.client_email_copy.review_intro }}

                    <br><br>

                    {{ $('Code in JavaScript5').item.json.client_email_copy.review_lead }}

                    <ul style="
                      padding-left:22px;
                      margin-top:18px;
                      margin-bottom:0;
                      color:#d0d0d0;
                      line-height:2;
                    ">
                      <li>{{ $('Code in JavaScript5').item.json.client_email_copy.scope_label }}</li>
                      <li>{{ $('Code in JavaScript5').item.json.client_email_copy.timeline_label }}</li>
                      <li>{{ $('Code in JavaScript5').item.json.client_email_copy.complexity_label }}</li>
                      <li>{{ $('Code in JavaScript5').item.json.client_email_copy.deliverables_label }}</li>
                    </ul>

                  </div>

                </div>

              </td>
            </tr>

            <!-- TASK -->
            <tr>
              <td style="padding:42px 52px 0 52px;">

                <div style="
                  border-top:1px solid rgba(255,255,255,0.06);
                  padding-top:36px;
                ">

                  <div style="
                    color:#7d7d7d;
                    font-size:11px;
                    letter-spacing:4px;
                    text-transform:uppercase;
                    margin-bottom:18px;
                    font-weight:600;
                  ">
                    {{ $('Code in JavaScript5').item.json.client_email_copy.submitted_task_label }}
                  </div>

                  <div style="
                    background:#111111;
                    border:1px solid rgba(255,255,255,0.06);
                    border-radius:18px;
                    padding:26px;
                    color:#f5f5f5;
                    font-size:17px;
                    line-height:1.9;
                    white-space:pre-wrap;
                    word-break:break-word;
                  ">
                    {{ $('Code in JavaScript5').item.json.client_email_task_description }}
                  </div>

                </div>

              </td>
            </tr>

            <!-- ATTACHMENTS -->
            {{ $('Code in JavaScript5').item.json.attachments_display ? `
            <tr>
              <td style="padding:24px 52px 0 52px;">

                <div style="
                  background:#101010;
                  border:1px solid rgba(255,255,255,0.06);
                  border-radius:18px;
                  padding:22px;
                ">

                  <div style="
                    color:#7d7d7d;
                    font-size:11px;
                    letter-spacing:3px;
                    text-transform:uppercase;
                    margin-bottom:12px;
                    font-weight:600;
                  ">
                    Attachments
                  </div>

                  <div style="
                    color:#ffffff;
                    font-size:15px;
                    line-height:1.8;
                    word-break:break-word;
                  ">
                    ${$('Code in JavaScript5').item.json.attachments_display}
                  </div>

                </div>

              </td>
            </tr>
            ` : '' }}

            <!-- DEADLINE -->
            <tr>
              <td style="padding:32px 52px 0 52px;">

                <table width="100%" cellpadding="0" cellspacing="0" border="0">

                  <tr>

                    <td width="50%" style="
                      padding-right:10px;
                      vertical-align:top;
                    ">

                      <div style="
                        background:#101010;
                        border:1px solid rgba(255,255,255,0.06);
                        border-radius:18px;
                        padding:22px;
                      ">

                        <div style="
                          color:#7d7d7d;
                          font-size:11px;
                          letter-spacing:3px;
                          text-transform:uppercase;
                          margin-bottom:12px;
                          font-weight:600;
                        ">
                          {{ $('Code in JavaScript5').item.json.client_email_copy.deadline_label }}
                        </div>

                        <div style="
                          color:#ffffff;
                          font-size:24px;
                          font-weight:600;
                        ">
                          {{ $('Extract Fields5').item.json.deadline }}
                        </div>

                      </div>

                    </td>

                    <td width="50%" style="
                      padding-left:10px;
                      vertical-align:top;
                    ">

                      <div style="
                        background:#101010;
                        border:1px solid rgba(255,255,255,0.06);
                        border-radius:18px;
                        padding:22px;
                      ">

                        <div style="
                          color:#7d7d7d;
                          font-size:11px;
                          letter-spacing:3px;
                          text-transform:uppercase;
                          margin-bottom:12px;
                          font-weight:600;
                        ">
                          {{ $('Code in JavaScript5').item.json.client_email_copy.review_window_label }}
                        </div>

                        <div style="
                          color:#ffffff;
                          font-size:24px;
                          font-weight:600;
                        ">
                          {{ $('Code in JavaScript5').item.json.client_email_copy.review_window_value }}
                        </div>

                      </div>

                    </td>

                  </tr>

                </table>

              </td>
            </tr>

            <!-- CTA -->
            <tr>
              <td style="padding:42px 52px;">

                <a 
                  href="{{ $('Code in JavaScript5').item.json.client_review_url }}"
                  style="
                    display:block;
                    background:#d6b36a;
                    color:#050505;
                    text-decoration:none;
                    text-align:center;
                    padding:20px;
                    border-radius:999px;
                    font-size:14px;
                    font-weight:700;
                    letter-spacing:3px;
                    text-transform:uppercase;
                  "
                >
                  {{ $('Code in JavaScript5').item.json.client_email_copy.cta }}
                </a>

              </td>
            </tr>

            <!-- FOOTER -->
            <tr>
              <td style="
                border-top:1px solid rgba(255,255,255,0.06);
                padding:28px 52px 42px 52px;
                color:#707070;
                font-size:12px;
                line-height:2;
                letter-spacing:2px;
                text-transform:uppercase;
                background:#0b0b0b;
              ">

                {{ $('Code in JavaScript5').item.json.client_email_copy.footer }}

              </td>
            </tr>

          </table>

        </td>
      </tr>
    </table>

  </body>
</html>
